fn solve(s: String, k: i64) -> String {
    let n = s.len();
    if n == 0 {
        return ".".to_string();
    }
    let mut lens_vec: Vec<i64> = Vec::with_capacity(n);
    let mut cur_len: i64 = 0;
    for c in s.chars() {
        cur_len = match c {
            '*' => {
                if cur_len > 0 {
                    cur_len - 1
                } else {
                    0
                }
            }
            '#' => {
                cur_len * 2
            }
            '%' => cur_len,
            _ => cur_len + 1,
        };
        lens_vec.push(cur_len);
    }
    let final_len = lens_vec[n - 1];
    if k < 0 || k >= final_len {
        return ".".to_string();
    }
    let mut cur_k = k;
    for i in (0..n).rev() {
        let c = s.chars().nth(i).unwrap();
        let len_here = lens_vec[i];
        match c {
            'a'..='z' => {
                if cur_k == len_here - 1 {
                    return c.to_string();
                }
            }
            '*' => {}
            '#' => {
                let half = len_here / 2;
                if cur_k >= half {
                    cur_k -= half;
                }
            }
            '%' => {
                cur_k = len_here - 1 - cur_k;
            }
            _ => {}
        }
    }
    ".".to_string()
}
